query:
-- 先将产品27的所有批次的isDefault设置为false
UPDATE product_variants SET isDefault = 0 WHERE productId = 27;

-- 然后将最早创建的批次设置为默认
UPDATE product_variants 
SET isDefault = 1 
WHERE id = (
  SELECT id FROM (
    SELECT id FROM product_variants 
    WHERE productId = 27 
    ORDER BY createdAt ASC 
    LIMIT 1
  ) AS temp
);

